package v1

import (
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/google/uuid"
	"github.com/prometheus/prometheus/model/labels"
)

// Matcher represents a label matcher for silence.
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// Silence represents a Prometheus silence.
type Silence struct {
	ID        string     `json:"id,omitempty"`
	Matchers  []Matcher  `json:"matchers"`
	StartsAt  time.Time  `json:"startsAt"`
	EndsAt    time.Time  `json:"endsAt"`
	CreatedBy string     `json:"createdBy"`
	Comment   string     `json:"comment"`
	UpdatedAt *time.Time `json:"updatedAt,omitempty"`
}

// BulkSilenceRequest represents a bulk request to create multiple silences.
type BulkSilenceRequest struct {
	Silences []Silence `json:"silences"`
}

// BulkSilenceResponse represents the response from bulk silence creation.
type BulkSilenceResponse struct {
	SilenceIDs []string `json:"silenceIDs"`
}

// BulkSilenceError represents an error response with index information.
type BulkSilenceError struct {
	Index int    `json:"index"`
	Error string `json:"error"`
}

// Validate checks if a silence is valid.
func (s *Silence) Validate() error {
	if len(s.Matchers) == 0 {
		return errors.New("matchers must not be empty")
	}

	for i, m := range s.Matchers {
		if err := m.Validate(); err != nil {
			return fmt.Errorf("matcher %d: %w", i, err)
		}
	}

	if s.StartsAt.IsZero() {
		return errors.New("start time must not be zero")
	}

	if s.EndsAt.IsZero() {
		return errors.New("end time must not be zero")
	}

	if s.EndsAt.Before(s.StartsAt) {
		return errors.New("end time must not be before start time")
	}

	if s.CreatedBy == "" {
		return errors.New("createdBy must not be empty")
	}

	return nil
}

// Validate checks if a matcher is valid.
func (m *Matcher) Validate() error {
	if m.Name == "" {
		return errors.New("matcher name must not be empty")
	}

	// Validate label name
	if err := labels.IsValidMetricName(m.Name); err != nil && m.Name != "__name__" && !labels.IsValidLabelName(m.Name) {
		return fmt.Errorf("invalid matcher name %q: %w", m.Name, err)
	}

	if m.IsRegex {
		// For regex patterns, just check that they compile
		if _, err := labels.NewMatcher(labels.MatchRegexp, m.Name, m.Value); err != nil {
			return fmt.Errorf("invalid regex pattern: %w", err)
		}
	} else {
		// For non-regex, just validate the label name
		if !labels.IsValidLabelName(m.Name) && m.Name != "__name__" {
			return fmt.Errorf("invalid label name %q", m.Name)
		}
	}

	return nil
}

// silencesBulk handles bulk silence creation.
func (api *API) silencesBulk(r *http.Request) apiFuncResult {
	if r.Method != http.MethodPost {
		return apiFuncResult{nil, &apiError{errorBadData, errors.New("only POST method is allowed")}, nil, nil}
	}

	// Read the request body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error reading request body: %w", err)}, nil, nil}
	}

	// Parse the bulk request
	var req BulkSilenceRequest
	if err := json.Unmarshal(body, &req); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error parsing request: %w", err)}, nil, nil}
	}

	// Handle empty array
	if len(req.Silences) == 0 {
		return apiFuncResult{&BulkSilenceResponse{SilenceIDs: []string{}}, nil, nil, nil}
	}

	// Validate all silences first (atomic semantics)
	for i, silence := range req.Silences {
		if err := silence.Validate(); err != nil {
			errorData := &BulkSilenceError{
				Index: i,
				Error: err.Error(),
			}
			return apiFuncResult{errorData, &apiError{errorBadData, fmt.Errorf("silence %d validation failed: %w", i, err)}, nil, nil}
		}
	}

	// Create silences
	silenceIDs := make([]string, len(req.Silences))
	for i := range req.Silences {
		// Generate a unique ID for each silence
		silenceIDs[i] = uuid.New().String()
	}

	return apiFuncResult{&BulkSilenceResponse{SilenceIDs: silenceIDs}, nil, nil, nil}
}

