)

// TestSilencesBulkSuccessfulCreation tests successful creation of multiple silences.
func TestSilencesBulkSuccessfulCreation(t *testing.T) {
	req := BulkSilenceRequest{
		Silences: []Silence{
			{
				Matchers: []Matcher{
					{Name: "job", Value: "prometheus", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Maintenance window",
			},
			{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(2 * time.Hour),
				CreatedBy: "user",
				Comment:   "Silencing test alert",
			},
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	httpReq.Header.Set("Content-Type", "application/json")

	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NoError(t, result.err)
	require.NotNil(t, result.data)

	resp, ok := result.data.(*BulkSilenceResponse)
	require.True(t, ok, "expected BulkSilenceResponse")
	require.Equal(t, 2, len(resp.SilenceIDs))

	// Verify that IDs are non-empty and unique
	for _, id := range resp.SilenceIDs {
		require.NotEmpty(t, id)
	}
	require.NotEqual(t, resp.SilenceIDs[0], resp.SilenceIDs[1])
}

// TestSilencesBulkEmptyArray tests that empty array is handled correctly.
func TestSilencesBulkEmptyArray(t *testing.T) {
	req := BulkSilenceRequest{
		Silences: []Silence{},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	httpReq.Header.Set("Content-Type", "application/json")

	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NoError(t, result.err)
	require.NotNil(t, result.data)

	resp, ok := result.data.(*BulkSilenceResponse)
	require.True(t, ok)
	require.Equal(t, 0, len(resp.SilenceIDs))
}

// TestSilencesBulkValidationFailure tests that validation errors are returned with index.
func TestSilencesBulkValidationFailure(t *testing.T) {
	testCases := []struct {
		name        string
		silences    []Silence
		errorIndex  int
		errorContains string
	}{
		{
			name: "empty matchers",
			silences: []Silence{
				{
					Matchers:  []Matcher{},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "admin",
					Comment:   "Test",
				},
			},
			errorIndex: 0,
			errorContains: "matchers must not be empty",
		},
		{
			name: "empty matcher name",
			silences: []Silence{
				{
					Matchers: []Matcher{
						{Name: "", Value: "test", IsRegex: false},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "admin",
					Comment:   "Test",
				},
			},
			errorIndex: 0,
			errorContains: "matcher name must not be empty",
		},
		{
			name: "zero start time",
			silences: []Silence{
				{
					Matchers: []Matcher{
						{Name: "job", Value: "test", IsRegex: false},
					},
					StartsAt:  time.Time{},
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "admin",
					Comment:   "Test",
				},
			},
			errorIndex: 0,
			errorContains: "start time must not be zero",
		},
		{
			name: "end before start",
			silences: []Silence{
				{
					Matchers: []Matcher{
						{Name: "job", Value: "test", IsRegex: false},
					},
					StartsAt:  time.Now().Add(1 * time.Hour),
					EndsAt:    time.Now(),
					CreatedBy: "admin",
					Comment:   "Test",
				},
			},
			errorIndex: 0,
			errorContains: "end time must not be before start time",
		},
		{
			name: "empty createdBy",
			silences: []Silence{
				{
					Matchers: []Matcher{
						{Name: "job", Value: "test", IsRegex: false},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "",
					Comment:   "Test",
				},
			},
			errorIndex: 0,
			errorContains: "createdBy must not be empty",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			req := BulkSilenceRequest{Silences: tc.silences}
			body, err := json.Marshal(req)
			require.NoError(t, err)

			httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
			api := &API{}
			result := api.silencesBulk(httpReq)

			require.NotNil(t, result.err)
			require.Contains(t, result.err.Error(), "validation failed")

			// Check error data
			errorData, ok := result.data.(*BulkSilenceError)
			require.True(t, ok)
			require.Equal(t, tc.errorIndex, errorData.Index)
			require.Contains(t, errorData.Error, tc.errorContains)
		})
	}
}

// TestSilencesBulkPartialValidationFailure tests error detection at specific index.
func TestSilencesBulkPartialValidationFailure(t *testing.T) {
	req := BulkSilenceRequest{
		Silences: []Silence{
			{
				Matchers: []Matcher{
					{Name: "job", Value: "prometheus", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Valid silence",
			},
			{
				// This one is missing createdBy
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "",
				Comment:   "Invalid silence",
			},
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NotNil(t, result.err)
	require.NotNil(t, result.data)

	errorData, ok := result.data.(*BulkSilenceError)
	require.True(t, ok)
	require.Equal(t, 1, errorData.Index)
	require.Contains(t, errorData.Error, "createdBy must not be empty")
}

// TestSilencesBulkInvalidJSON tests that invalid JSON is properly handled.
func TestSilencesBulkInvalidJSON(t *testing.T) {
	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader([]byte("invalid json")))
	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NotNil(t, result.err)
	require.Contains(t, result.err.Error(), "parsing request")
}

// TestSilencesBulkRegexMatcher tests validation of regex matchers.
func TestSilencesBulkRegexMatcher(t *testing.T) {
	// Valid regex
	req := BulkSilenceRequest{
		Silences: []Silence{
			{
				Matchers: []Matcher{
					{Name: "job", Value: "prometheus|alertmanager", IsRegex: true},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Valid regex",
			},
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NoError(t, result.err)

	resp, ok := result.data.(*BulkSilenceResponse)
	require.True(t, ok)
	require.Equal(t, 1, len(resp.SilenceIDs))
}

// TestSilencesBulkInvalidRegex tests that invalid regex patterns are rejected.
func TestSilencesBulkInvalidRegex(t *testing.T) {
	req := BulkSilenceRequest{
		Silences: []Silence{
			{
				Matchers: []Matcher{
					{Name: "job", Value: "[invalid(regex", IsRegex: true},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Invalid regex",
			},
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NotNil(t, result.err)

	errorData, ok := result.data.(*BulkSilenceError)
	require.True(t, ok)
	require.Equal(t, 0, errorData.Index)
	require.Contains(t, errorData.Error, "regex")
}

// TestSilenceValidator tests the Silence validation logic.
func TestSilenceValidator(t *testing.T) {
	testCases := []struct {
		name    string
		silence Silence
		isValid bool
		errorMsg string
	}{
		{
			name: "valid silence",
			silence: Silence{
				Matchers: []Matcher{
					{Name: "job", Value: "test", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Test",
			},
			isValid: true,
		},
		{
			name: "no matchers",
			silence: Silence{
				Matchers:  []Matcher{},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Test",
			},
			isValid: false,
			errorMsg: "matchers must not be empty",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			err := tc.silence.Validate()
			if tc.isValid {
				require.NoError(t, err)
			} else {
				require.Error(t, err)
				require.Contains(t, err.Error(), tc.errorMsg)
			}
		})
	}
}

// TestMatcherValidator tests the Matcher validation logic.
func TestMatcherValidator(t *testing.T) {
	testCases := []struct {
		name    string
		matcher Matcher
		isValid bool
		errorMsg string
	}{
		{
			name:    "valid simple matcher",
			matcher: Matcher{Name: "job", Value: "test", IsRegex: false},
			isValid: true,
		},
		{
			name:    "valid regex matcher",
			matcher: Matcher{Name: "alertname", Value: "TestAlert.*", IsRegex: true},
			isValid: true,
		},
		{
			name:    "empty name",
			matcher: Matcher{Name: "", Value: "test", IsRegex: false},
			isValid: false,
			errorMsg: "matcher name must not be empty",
		},
		{
			name:    "invalid regex",
			matcher: Matcher{Name: "job", Value: "[invalid", IsRegex: true},
			isValid: false,
			errorMsg: "regex",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			err := tc.matcher.Validate()
			if tc.isValid {
				require.NoError(t, err)
			} else {
				require.Error(t, err)
				if tc.errorMsg != "" {
					require.Contains(t, err.Error(), tc.errorMsg)
				}
			}
		})
	}
}

